public int[][] highestIsland(int[][] isWater) {
    int m = isWater.length;
    int n = isWater[0].length;
    int[][] height = new int[m][n];
    Queue<int[]> q = new LinkedList<>();

    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (isWater[i][j] == 1) {
                height[i][j] = 0;
                q.offer(new int[]{i, j});
            } else {
                height[i][j] = -1;
            }
        }
    }

    int[] dx = {-1, 0, 1, 0};
    int[] dy = {0, 1, 0, -1};

    while (!q.isEmpty()) {
        int[] curr = q.poll();
        int x = curr[0];
        int y = curr[1];

        for (int i = 0; i < 4; i++) {
            int newX = x + dx[i];
            int newY = y + dy[i];

            if (newX >= 0 && newX < m && newY >= 0 && newY < n && height[newX][newY] == -1) {
                height[newX][newY] = height[x][y] + 1;
                q.offer(new int[]{newX, newY});
            }
        }
    }

    return height;
}
