public class Solution {
    public ListNode reverseGroup(ListNode head, int k) {
        if (head == null || k == 1) return head;
        ListNode prev = null;
        ListNode cur = head;
        for (int i = 0; i < k; i++) {
            ListNode next = cur.next;
            cur.next = prev;
            prev = cur;
            cur = next;
        }
        head.next = cur;
        return prev;
    }

    public ListNode reverseEvenGroups(ListNode head) {
        ListNode dummy = new ListNode(0);
        dummy.next = head;
        ListNode prev = dummy;
        int n = 0;
        for (ListNode cur = head; cur != null; cur = cur.next)
            n++;
        for (int i = 1, k = 1; n >= 0 && k <= n; i++, k += i) {
            if (i % 2 == 0) {
                ListNode tail = prev.next;
                ListNode next = prev.next;
                for (int j = 0; j < k; j++)
                    next = next.next;
                prev.next = reverseGroup(tail, k);
                tail.next = next;
            }
            n -= k;
            for (int j = 0; j < k && prev != null; j++)
                prev = prev.next;
        }
        return dummy.next;
    }
}
