int minimumScore(int n, vector<vector<int>>& roads) {
    vector<vector<pair<int, int>>> adj(n + 1);
    for (const auto& road : roads) {
        adj[road[0]].push_back({road[1], road[2]});
        adj[road[1]].push_back({road[0], road[2]});
    }

    const int INF = 1e9;
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<>> pq;
    pq.push({0, 1});

    vector<int> minDist(n + 1, INF);
    while (!pq.empty()) {
        int curCity = pq.top().second;
        int curDist = pq.top().first;
        pq.pop();

        if (curCity == n) {
            return curDist;
        }

        if (curDist < minDist[curCity]) {
            minDist[curCity] = curDist;
            for (const auto& neighbor : adj[curCity]) {
                int nextCity = neighbor.first;
                int nextDist = max(curDist, neighbor.second);
                if (nextDist < minDist[nextCity]) {
                    pq.push({nextDist, nextCity});
                }
            }
        }
    }

    return -1;
}
