int threeSumMulti(std::vector<int>& arr, int target) {
    const int MOD = 1000000007;
    long long ans = 0;

    sort(arr.begin(), arr.end());
    int n = arr.size();

    for (int i = 0; i < n - 2; ++i) {
        int j = i + 1, k = n - 1;
        while (j < k) {
            int sum = arr[i] + arr[j] + arr[k];
            if (sum > target) {
                k--;
            } else if (sum < target) {
                j++;
            } else {
                if (arr[j] != arr[k]) {
                    int left_count = 1, right_count = 1;

                    while (arr[j] == arr[j + 1]){
                        left_count++; 
                        j++;
                    }
                    while (arr[k] == arr[k - 1]){
                        right_count++;
                        k--;
                    }

                    ans += left_count * right_count;
                    ans %= MOD;
                    j++, k--;
