public String validateIP(String queryIP) {
    String[] ipv4Parts = queryIP.split("\\.", -1);
    String[] ipv6Parts = queryIP.split(":", -1);

    if (ipv4Parts.length == 4) {
        if (isValidIPv4(ipv4Parts)) return "IPv4";
