import java.util.LinkedList;
import java.util.Queue;

public int shortestCycleLength(int n, int[][] edges) {
    ArrayList<ArrayList<Integer>> graph = new ArrayList<>();
    for (int i = 0; i < n; ++i) {
        graph.add(new ArrayList<>());
    }
    for (int[] edge : edges) {
        graph.get(edge[0]).add(edge[1]);
        graph.get(edge[1]).add(edge[0]);
    }

    int shortestCycle = n + 1;
    for (int start = 0; start < n; ++start) {
        int[] dist = new int[n];
        for (int i = 0; i < n; ++i) {
            dist[i] = n + 1;
        }
        dist[start] = 0;
        Queue<Integer> queue = new LinkedList<>();
        queue.offer(start);

        while (!queue.isEmpty()) {
            int cur = queue.poll();
            for (int neigh : graph.get(cur)) {
                if (dist[neigh] == n + 1) {
                    dist[neigh] = dist[cur] + 1;
                    queue.offer(neigh);
                } else if (dist[neigh] >= dist[cur] - 1) {
                    shortestCycle = Math.min(shortestCycle, dist[cur] + dist[neigh] + 1);
                }
            }
        }
    }

    return shortestCycle == n + 1 ? -1 : shortestCycle;
}
